<template><div class="page"><header class="page-head"><div><h1>Notifications</h1><p>Historique des envois et erreurs recentes.</p></div><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></header><p v-if="error" class="notice error-text">{{ error }}</p><section class="panel table-wrap"><table><thead><tr><th>Date</th><th>Evenement</th><th>Media</th><th>Destinataire</th><th>Etat</th><th></th></tr></thead><tbody><tr v-for="row in rows" :key="row.id"><td>{{ formatDate(row.sent_at) }}</td><td>{{ row.event_label||row.event }}</td><td>{{ row.media_title||'-' }}</td><td>{{ row.recipient }}</td><td><span class="badge" :class="row.success?'available':'failed'">{{ row.status_label }}</span></td><td><button v-if="!row.success" class="icon-button" title="Renvoyer" @click="resend(row)"><Send /></button></td></tr></tbody></table><p v-if="!loading&&rows.length===0" class="empty">Aucune notification.</p></section></div></template>
<script setup>import { onMounted,ref } from "vue";import { RefreshCw,Send } from "@lucide/vue";import { api } from "@/api";import { useRealtime } from "@/events";const rows=ref([]),loading=ref(false),error=ref("");function formatDate(v){return v?new Intl.DateTimeFormat('fr-FR',{dateStyle:'short',timeStyle:'short'}).format(new Date(v)):'-'}async function load(){loading.value=true;error.value="";try{rows.value=(await api('/api/notifications/log?limit=100')).items}catch(e){error.value=e.message}finally{loading.value=false}}async function resend(row){try{await api(`/api/notifications/${row.id}/resend`,{method:'POST'});await load()}catch(e){error.value=e.message}}useRealtime(['notification.updated'],load);onMounted(load);</script>
